#!/usr/bin/env bash
set -euo pipefail; source "$(dirname "$0")/lib/android-test.sh"; serial=emulator-5554; source_package=; target=org.archphene.linux.mousepad; tag=ArchpheneMousepad; timeout=35; while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--source-package)source_package="${2:?}";shift 2;;--target-package)target="${2:?}";shift 2;;--target-log-tag)tag="${2:?}";shift 2;;--timeout-seconds)timeout="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done; archphene_test_init "$serial"; manager=org.archpheneos.manager; archphene_adb_run shell pm path "$manager" >/dev/null; component="$(archphene_launcher "$target")"; if [[ -z "$source_package" ]];then rows="$(archphene_adb_run shell content query --uri content://org.archpheneos.manager.documents/document/apps/children)";source_package="$(python3 -c 'import re,sys;m=re.search(r"document_id=app/(org\.archphene\.linux\.p[a-f0-9]{32})/home",sys.stdin.read());print(m.group(1) if m else "")'<<<"$rows")";fi;[[ -n "$source_package" ]] || archphene_die 'no generated GUI wrapper installed'; archphene_adb_run logcat -c; archphene_adb_run shell am start -n "$manager/.MainActivity" --es archphene_test_gui_documents "$source_package" >/dev/null; archphene_wait_log "GUI document broker passed package=$source_package" "$timeout" "ArchpheneDocuments $tag AndroidRuntime *:S" >/dev/null; archphene_adb_run logcat -c; archphene_adb_run shell am start -n "$component" --es archphene_test_private_broker_authority "$source_package.documents" >/dev/null; denial="$(archphene_wait_log 'Private GUI home provider' "$timeout" "ArchpheneDocuments $tag AndroidRuntime *:S")"; archphene_regex_contains "$denial" 'denied unauthorized caller|unavailable to unauthorized caller' || archphene_die 'private provider did not deny caller'; archphene_adb_run logcat -c; archphene_adb_run shell am start -n "$manager/.MainActivity" --es archphene_test_document_session_source "$source_package" --es archphene_test_document_session_target "$target" >/dev/null; archphene_wait_log 'Running document restart probe passed documents=2' "$timeout" "ArchpheneDocuments $tag AndroidRuntime *:S" >/dev/null; archphene_note "GUI document broker passed on $serial."
